const leads = $input.all();
const now = new Date();
const results = [];

const CADENCE = {
  hot:     [2, 4],
  warm:    [2, 5, 9, 14, 21],
  cool:    [3, 7, 14, 21, 30],
  not_fit: []
};

const STOP_STATUSES = ['engaged','closed','unsubscribed','nurture_complete','rejected','editing_manual'];

for (const item of leads) {
  const lead = item.json;
  const status = (lead.status || '').toLowerCase();
  if (STOP_STATUSES.includes(status)) continue;

  const tier = (lead.icp_class || 'warm').toLowerCase();
  const cadence = CADENCE[tier];
  if (!cadence || cadence.length === 0) continue;

  const stage = parseInt(lead.nurture_stage) || 0;
  const nextDay = cadence[stage];
  if (nextDay === undefined || nextDay === null) continue;

  const submittedAt = new Date(lead.submitted_at || lead.timestamp);
  if (isNaN(submittedAt.getTime())) continue;
  const daysSinceSubmission = Math.floor((now - submittedAt) / (1000 * 60 * 60 * 24));
  if (daysSinceSubmission < nextDay) continue;

  const lastSent = lead.last_email_sent ? new Date(lead.last_email_sent) : null;
  if (lastSent && !isNaN(lastSent.getTime()) && lastSent.toDateString() === now.toDateString()) continue;

  if (stage === 5 && tier !== 'cool') continue;

  const unsubLink = 'https://n8nbeginner-sga.app.n8n.cloud/webhook/da-unsubscribe?lead_id=' + encodeURIComponent(lead.lead_id);
  const firstName = lead.first_name || (lead.name || '').split(' ')[0] || 'there';

  results.push({ json: {
    ...lead,
    next_stage: stage + 1,
    stage_to_send: String(stage),
    unsub_link: unsubLink,
    first_name: firstName,
    days_since_submission: daysSinceSubmission
  }});
}

return results;

const lead = $input.first().json;
const now = new Date().toISOString();
const maxStage = {hot: 2, warm: 5, cool: 6, not_fit: 0}[(lead.icp_class || 'warm').toLowerCase()] || 5;

return [{ json: {
  lead_id: lead.lead_id,
  nurture_stage: lead.next_stage,
  last_email_sent: now,
  status: lead.next_stage >= maxStage ? 'nurture_complete' : (lead.status || 'new')
}}];
